#!/usr/bin/env bash
set -euo pipefail

API_KEY="${OPENCODE_API_KEY:?OPENCODE_API_KEY is not set}"
ENDPOINT="https://opencode.ai/zen/go/v1/chat/completions"
MODEL="kimi-k2.6"

echo "=== 1. Plain text call (max_tokens=500) ==="
curl -s "$ENDPOINT" \
  -H "Content-Type: application/json" \
  -H "Authorization: Bearer $API_KEY" \
  -d "{
    \"model\": \"$MODEL\",
    \"messages\": [
      {\"role\": \"system\", \"content\": \"Reply in one short sentence.\"},
      {\"role\": \"user\", \"content\": \"Say hello.\"}
    ],
    \"temperature\": 0.2,
    \"max_tokens\": 500
  }" | python3 -m json.tool

echo ""
echo "=== 2. Vision call (100x100 red JPEG, max_tokens=800) ==="
IMG_B64=""

curl -s "$ENDPOINT" \
  -H "Content-Type: application/json" \
  -H "Authorization: Bearer $API_KEY" \
  -d "{
    \"model\": \"$MODEL\",
    \"messages\": [
      {\"role\": \"system\", \"content\": \"Describe ONLY what is visible. Keep it under 30 words.\"},
      {\"role\": \"user\", \"content\": [
        {\"type\": \"text\", \"text\": \"What do you see?\"},
        {\"type\": \"image_url\", \"image_url\": {\"url\": \"data:image/jpeg;base64,$IMG_B64\"}}
      ]}
    ],
    \"temperature\": 0.2,
    \"max_tokens\": 800
  }" | python3 -m json.tool
